/* ─── Types ─── */
interface MediaSlot {
  src?: string;
  badge?: string;
  placeholderLabel?: string;
  height?: number;
  objectFit?: 'cover' | 'contain' | 'fill' | 'scale-down' | 'none';
}

interface StatItem {
  value: string;
  label: string;
}

interface AvatarItem {
  initials: string;
  color: string;
  bg: string;
}

interface BentoCard {
  id: string;
  label?: string;
  title: string;
  description: string;
  // Icon support: backward compatible
  iconSvg?: string;           // Legacy: inline SVG
  iconConfig?: IconConfig;    // New: FontAwesome via IconPicker
  iconBg?: string;
  iconColor?: string;
  stats?: StatItem[];
  media?: MediaSlot;
  mediaPosition?: 'top' | 'bottom';
  avatars?: AvatarItem[];
  avatarExtra?: string;
  isTeamCard?: boolean;
  colSpan?: 1 | 2;
}

interface TickerItem {
  text: string;
  iconConfig?: IconConfig; // FontAwesome icon (optional)
}

// Type guard to check if ticker item is old format (string) or new format (object)
type TickerItemInput = string | TickerItem;

function normalizeTickerItem(item: TickerItemInput): TickerItem {
  if (typeof item === 'string') {
    return { text: item }; // Backward compatibility: convert string to object
  }
  return item;
}

interface WhyAutomateWithUsSectionData {
  eyebrow?: string;
  title?: string;
  titleHighlight?: string;
  subtitle?: string;
  accentColor?: string;
  accentColor2?: string;
  accentColor3?: string;
  /* Row layout: row1 = 2 cols, row2 = 3 cols, row3 = 2 cols */
  row1Cards?: BentoCard[];
  row2Cards?: BentoCard[];
  row3Cards?: BentoCard[];
  tickerItems?: TickerItemInput[];
  tickerSpeed?: number;
  sectionPaddingY?: string;
}

interface WhyAutomateWithUsSectionProps {
  data: WhyAutomateWithUsSectionData;
  style?: { backgroundColor?: string; textColor?: string; padding?: string };
  isBuilder?: boolean;
}

