/* ─── Helper: Media Slot ─── */
function MediaSlotRenderer({
  media,
  accent,
}: {
  media: MediaSlot;
  accent: string;
}) {
  const isVideo = (src: string) =>
    ['.mp4', '.webm', '.ogg', '.mov'].some(e => src.toLowerCase().includes(e));

  const h = media.height ?? 200;
  const fit = media.objectFit ?? 'cover';

  return (
    <div
      className="relative w-full overflow-hidden border-t border-slate-200 dark:border-white/[0.07] bg-slate-100 dark:bg-[#0E1014] flex flex-col items-center justify-center gap-3"
      style={{ height: h }}
    >
      {/* shimmer overlay */}
      <div
        className="pointer-events-none absolute inset-0"
        style={{ background: 'linear-gradient(135deg, rgba(79,127,255,0.03) 0%, rgba(123,92,255,0.03) 100%)' }}
      />

      {media.src ? (
        isVideo(media.src) ? (
          <video
            src={media.src}
            className="absolute inset-0 w-full h-full"
            style={{ objectFit: fit }}
            autoPlay
            muted
            loop
            playsInline
          />
        ) : (
          <img
            src={media.src}
            alt={media.badge ?? ''}
            className="absolute inset-0 w-full h-full"
            style={{ objectFit: fit }}
          />
        )
      ) : (
        <>
          <div
            className="relative z-10 w-12 h-12 rounded-[14px] flex items-center justify-center"
            style={{ background: 'rgba(79,127,255,0.1)', border: '1.5px solid rgba(79,127,255,0.2)' }}
          >
            <svg viewBox="0 0 24 24" fill="none" stroke={accent} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" className="w-5 h-5">
              <rect x="3" y="3" width="18" height="18" rx="2" />
              <circle cx="8.5" cy="8.5" r="1.5" />
              <polyline points="21 15 16 10 5 21" />
            </svg>
          </div>
          <span className="relative z-10 text-[12px] font-medium text-slate-400 dark:text-[#4A4F65] tracking-wide">
            {media.placeholderLabel ?? 'Add media'}
          </span>
        </>
      )}

      {media.badge && (
        <span
          className="absolute top-3 right-3 z-20 text-[10px] font-semibold tracking-[0.1em] uppercase rounded-full px-3 py-1"
          style={{ color: accent, background: 'rgba(79,127,255,0.1)', border: '1px solid rgba(79,127,255,0.2)' }}
        >
          {media.badge}
        </span>
      )}
    </div>
  );
}

/* ─── Helper: Bento Card ─── */
function BentoCardRenderer({
  card,
  accent,
  accent2,
  accent3,
}: {
  card: BentoCard;
  accent: string;
  accent2: string;
  accent3: string;
}) {
  const gradientStat = `linear-gradient(120deg, ${accent} 0%, ${accent2} 100%)`;

  return (
    <div
      className="group relative overflow-hidden rounded-3xl flex flex-col transition-all duration-300
        bg-slate-50 dark:bg-[#1A1D24]
        border border-slate-200 dark:border-white/[0.07]
        hover:border-slate-300 dark:hover:border-white/[0.13]
        hover:-translate-y-1
        hover:shadow-[0_24px_60px_rgba(0,0,0,0.1)]
        dark:hover:shadow-[0_24px_60px_rgba(0,0,0,0.4)]"
      style={card.isTeamCard ? {
        background: 'linear-gradient(135deg, rgba(79,127,255,0.05) 0%, rgba(123,92,255,0.04) 100%)',
        borderColor: 'rgba(79,127,255,0.15)',
      } : undefined}
    >
      {/* top gradient line on hover */}
      <div
        className="absolute top-0 left-0 right-0 h-[1.5px] opacity-0 group-hover:opacity-100 transition-opacity duration-300 z-10"
        style={{ background: `linear-gradient(90deg, transparent, ${accent}, ${accent2}, transparent)` }}
      />
      {/* glow orb */}
      <div
        className="pointer-events-none absolute -top-24 -right-24 w-72 h-72 rounded-full opacity-0 group-hover:opacity-100 transition-opacity duration-400"
        style={{ background: `radial-gradient(circle, rgba(79,127,255,0.09) 0%, transparent 70%)` }}
      />

      {/* media top */}
      {card.media && card.mediaPosition === 'top' && (
        <MediaSlotRenderer media={card.media} accent={accent} />
      )}

      {/* body */}
      <div className="flex-1 flex flex-col p-8 md:p-9 relative z-10">
        {/* avatars */}
        {card.avatars && (
          <div className="flex items-center mb-5">
            {card.avatars.map((av, i) => (
              <div
                key={i}
                className="w-10 h-10 rounded-full flex items-center justify-center text-[12px] font-bold flex-shrink-0 border-2 border-white dark:border-[#07080A]"
                style={{ background: av.bg, color: av.color, marginRight: i < card.avatars!.length - 1 ? '-10px' : '0' }}
              >
                {av.initials}
              </div>
            ))}
            {card.avatarExtra && (
              <div
                className="w-10 h-10 rounded-full flex items-center justify-center text-[11px] font-semibold flex-shrink-0 border-2 border-white dark:border-[#07080A] ml-3"
                style={{ background: 'rgba(255,255,255,0.08)', color: '#8A8FA8' }}
              >
                {card.avatarExtra}
              </div>
            )}
          </div>
        )}

        {/* icon - backward compatible: iconConfig (new) or iconSvg (legacy) */}
        {(card.iconConfig || card.iconSvg) && (
          <div
            className="w-[46px] h-[46px] rounded-[13px] flex items-center justify-center mb-5 flex-shrink-0"
            style={{ background: card.iconBg ?? 'rgba(79,127,255,0.08)', border: '1.5px solid rgba(255,255,255,0.07)', color: card.iconColor ?? accent }}
          >
            {card.iconConfig ? (
              <IconDisplay icon={card.iconConfig} className="text-xl" />
            ) : (
              <div dangerouslySetInnerHTML={{ __html: card.iconSvg! }} />
            )}
          </div>
        )}

        {/* label */}
        {card.label && (
          <p
            className="text-[11px] font-semibold tracking-[0.14em] uppercase mb-2.5"
            style={{ color: accent }}
          >
            {card.label}
          </p>
        )}

        {/* title */}
        <h3 className="font-bold text-[20px] md:text-[22px] leading-[1.25] tracking-tight text-slate-900 dark:text-[#F0F2F8] mb-3">
          {card.title}
        </h3>

        {/* description */}
        <p className="text-[14px] leading-[1.72] font-light text-slate-500 dark:text-[#8A8FA8] flex-1">
          {card.description}
        </p>

        {/* stats */}
        {card.stats && card.stats.length > 0 && (
          <div
            className="flex flex-wrap gap-6 mt-7 pt-6 border-t border-slate-200 dark:border-white/[0.07]"
          >
            {card.stats.map((s, i) => (
              <div key={i}>
                <div
                  className="font-extrabold text-[26px] leading-none mb-1"
                  style={{ background: gradientStat, WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', backgroundClip: 'text' }}
                >
                  {s.value}
                </div>
                <div className="text-[12px] text-slate-400 dark:text-[#4A4F65]">{s.label}</div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* media bottom */}
      {card.media && card.mediaPosition === 'bottom' && (
        <MediaSlotRenderer media={card.media} accent={accent} />
      )}
    </div>
  );
}

